class IndexCache:
    def __init__(self):
        self.caches = {}

    def get_cache(self, index_file):
        if index_file not in self.caches:
            self.caches[index_file] = {}
        return self.caches[index_file]

    def put_cache(self, index_file, key, value):
        self.caches[index_file][key] = value

    def delete_cache(self, index_file, key):
        if index_file in self.caches:
            if key in self.caches[index_file]:
                del self.caches[index_file][key]

    def delete_index_cache(self, index_file):
        if index_file in self.caches:
            del self.caches[index_file]
```

